def create_ticket_tool(params):
    ticket_data = {
        'customer_id': params['customer_id'],
        'issue_type': params['issue_type'],
        'priority': params['priority'],
        'description': params['description']
    }
    response = crm_api.create_ticket(ticket_data)
    return {
        'ticket_id': response['id'],
        'status': response['status'],
        'url': response['view_url']
    }

def lookup_order_tool(params):
    order = crm_api.get_order(params['order_id'])
    return {
        'order_id': order['id'],
        'status': order['status'],
        'total': order['total'],
        'items': order['items']
    }

stack.register_tools([create_ticket_tool, lookup_order_tool])

